CHR:NomadEnvironment.GetTrace().Info("IDIOMAS");
double dblResNivel = 0d;
double dblResultado = 0d;
double dblPesoIdioma;
double dblPesoTotal = 0d;
IDIOMA_CV objIdiomaCV;
NomadXML xmlIdiomasP;

xmlIdiomasP = this.GetIdiomasPuesto();
pbolExcluir = false;

//Obtiene el Peso Total
dblPesoTotal = xmlIdiomasP.GetAttrDouble("peso_total");

for (NomadXML xmlIdioma = xmlIdiomasP.FirstChild(); xmlIdioma != null; xmlIdioma = xmlIdioma.Next()) {
	objIdiomaCV = (IDIOMA_CV)pobjCV.IDIOMAS_CV.GetByAttribute("oi_idioma", xmlIdioma.GetAttr("oi_idioma"));
	dblResNivel = 0;
	
	if (objIdiomaCV != null) {
		
		//Nivel escritura
		if (objIdiomaCV.c_nivel_escribe == xmlIdioma.GetAttr("c_nivel_escribe"))
			dblResNivel = dblResNivel + 1;
		else
			dblResNivel = dblResNivel + ((int.Parse(objIdiomaCV.c_nivel_escribe) < int.Parse(xmlIdioma.GetAttr("c_nivel_escribe"))) ? 0.8d : 1.2d);

		//Nivel lectura
		if (objIdiomaCV.c_nivel_lee == xmlIdioma.GetAttr("c_nivel_lee"))
			dblResNivel = dblResNivel + 1;
		else
			dblResNivel = dblResNivel + ((int.Parse(objIdiomaCV.c_nivel_lee) < int.Parse(xmlIdioma.GetAttr("c_nivel_lee"))) ? 0.8d : 1.2d);

		//Nivel escritura
		if (objIdiomaCV.c_nivel_habla == xmlIdioma.GetAttr("c_nivel_habla"))
			dblResNivel = dblResNivel + 1;
		else
			dblResNivel = dblResNivel + ((int.Parse(objIdiomaCV.c_nivel_habla) < int.Parse(xmlIdioma.GetAttr("c_nivel_habla"))) ? 0.8d : 1.2d);
		
		dblPesoIdioma = xmlIdioma.GetAttrDouble("e_peso");

	} else {
		dblPesoIdioma = 0d;
	}

	//Pregunta si el idioma requerido es excluyente
	if (xmlIdioma.GetAttrBool("l_excluyente") && dblResNivel < 1) {
		pbolExcluir = true;
		break;
	}

	//Se divide por tres (escribe, lee y habla)
	dblResNivel = (dblResNivel / 3) * (dblPesoIdioma / dblPesoTotal);

	dblResultado = dblResultado + dblResNivel;
}

dblResultado = dblResultado * pdblPonderacion;

NomadEnvironment.GetTrace().Info("RESULTADO -- " + dblResultado + " - Exluye - " + pbolExcluir);
return dblResultado;

CHR:NomadEnvironment.GetTrace().Info("Conocimientos Informáticos");
double dblResInfor = 0d;
double dblResultado = 0d;
NomadXML xmlInformaticaP;
INFORMATICA_CV objInforCV;

xmlInformaticaP = this.GetConocInfPuesto();
pbolExcluir = false;

//Recorre los Puesto requeridos por el puesto y los busca en el CV
for (NomadXML xmlInforP = xmlInformaticaP.FirstChild(); xmlInforP != null; xmlInforP = xmlInforP.Next()) {
	
	//Busca la el conocimiento de informatica dentro del CV
	objInforCV = (INFORMATICA_CV) pobjCV.INFORMATICA.GetByAttribute("oi_informatica", xmlInforP.GetAttr("oi_informatica"));

	if (objInforCV == null)
		dblResInfor = 0d;
	else
		if (objInforCV.c_nivel == xmlInforP.GetAttr("c_nivel")) {
			dblResInfor = 1d;
		} else {
			if (int.Parse(objInforCV.c_nivel) < int.Parse(xmlInforP.GetAttr("c_nivel")))
				dblResInfor = 0.60d;
			else
				dblResInfor = 1.25d;
		}

	//Calcula el resultado del area
	dblResInfor = dblResInfor / xmlInformaticaP.ChildLength;

	dblResultado = dblResultado + dblResInfor;
}

dblResultado = dblResultado * pdblPonderacion;

NomadEnvironment.GetTrace().Info("RESULTADO -- " + dblResultado + " - Exluye - " + pbolExcluir);

return dblResultado;

CHR:NomadEnvironment.GetTrace().Info("Estudios");
double dblResEstudio = 0d;
double dblResultado = 0d;
double dblPesoEstudio;
double dblPesoTotal = 0d;
double dblPesoEstudioCV = 0d;
double dblPesoAreaCV = 0d;
ArrayList arrEstudiosCV;
NomadXML xmlEstudiosP;

xmlEstudiosP = this.GetEstudiosPuesto();
pbolExcluir = false;

//Obtiene el Peso Total
dblPesoTotal = xmlEstudiosP.GetAttrDouble("peso_total");

//Valida la division por 0 (cero)
if (dblPesoTotal == 0) return 0d;

//Recorre los Estudios del puesto y los busca en el CV
for (NomadXML xmlEstudioP = xmlEstudiosP.FirstChild(); xmlEstudioP != null; xmlEstudioP = xmlEstudioP.Next()) {
	//Pide los estudios del CV que pertenezcan al area solicitada
	arrEstudiosCV = this.GetEstudiosXAreaCV(pobjCV, xmlEstudioP.GetAttr("oi_area_est"));
	
	//Valida que tenga el area (Si existe le suma un 30% del peso del estudio)	
	if (arrEstudiosCV.Count > 0) {
		dblPesoAreaCV = 0.30d;
		dblPesoEstudioCV = 0d;

		//Busca el estudio pedido por el puesto dentro de los que cargo el CV (y que sea dentro del mismo area). Si lo encuentra le suma un 70% del peso del estudio.
		string estado = "";
		foreach (ESTUDIO_CV objEstudioCV in arrEstudiosCV) {
			if (!objEstudioCV.oi_estudioNull && objEstudioCV.oi_estudio.ToString() == xmlEstudioP.GetAttr("oi_estudio")) {
				dblPesoEstudioCV = 0.70d;
				estado = objEstudioCV.c_estado;
				break;
			}
			if(estado == "" || int.Parse(estado) < int.Parse(objEstudioCV.c_estado))
				estado = objEstudioCV.c_estado;
		}

		switch (estado) {
			case "1": dblResEstudio = 1d; break;    //Completo
			case "2": dblResEstudio = 0.60d; break; //Incompleto
			case "3": dblResEstudio = 0.85d; break; //En Curso
		}

		//El peso se calculara segun el estado multiplicado por el peso del area + el peso del estudio.
		dblResEstudio = dblResEstudio * (dblPesoAreaCV + dblPesoEstudioCV);

		dblPesoEstudio = xmlEstudioP.GetAttrDouble("e_peso");

		//Pregunta si el estudio requerido es excluyente
		if (xmlEstudioP.GetAttrBool("l_excluyente") && dblResEstudio == 0d) {
			pbolExcluir = true;
			break;
		}

		//Calcula el resultado del area
		dblResEstudio = dblResEstudio * (dblPesoEstudio / dblPesoTotal);


	}  else {
		dblPesoAreaCV = 0d;
		dblPesoEstudioCV = 0d;
		dblResEstudio = 0d;
	}
	dblResultado = dblResultado + dblResEstudio;
}

dblResultado = dblResultado * pdblPonderacion;

NomadEnvironment.GetTrace().Info("RESULTADO -- " + dblResultado + " - Exluye - " + pbolExcluir);

return dblResultado;

CHR:NomadEnvironment.GetTrace().Info("EXPERIENCIA");
double dblResExp = 0d;
double dblResultado = 0d;
double dblPesoExp;
double dblPesoTotal = 0d;
double dblDiasPuesto;
Hashtable htaDiasExpCV = new Hashtable();
Hashtable htaAreasExpCV = new Hashtable();
NomadXML xmlExperienciasP;
xmlExperienciasP = this.GetExpPuesto();
pbolExcluir = false;
{
	TimeSpan tsDiferencia;
	//Recorre la experiencia del CV y acumula los dias por cada puesto
	foreach (EXPERIENCIA objExpCV in pobjCV.EXPERIENCIA) 
	{
		//Calcula la cantidad en dias de la experiencia
		if (objExpCV.f_egresoNull)
			tsDiferencia = DateTime.Now.Subtract(objExpCV.f_ingreso);
		else
			tsDiferencia = objExpCV.f_egreso.Subtract(objExpCV.f_ingreso);
		if (htaDiasExpCV.ContainsKey(objExpCV.oi_puesto_exp))
			htaDiasExpCV[objExpCV.oi_puesto_exp] = ((double) htaDiasExpCV[objExpCV.oi_puesto_exp]) + tsDiferencia.TotalDays;
		else
			htaDiasExpCV[objExpCV.oi_puesto_exp] = tsDiferencia.TotalDays;		
		if (htaAreasExpCV.ContainsKey(objExpCV.oi_puesto_exp))
			htaAreasExpCV[objExpCV.oi_puesto_exp] = objExpCV.oi_area_exp;
		else
			htaAreasExpCV[objExpCV.oi_puesto_exp] = objExpCV.oi_area_exp;
	}
}
//Obtiene el Peso Total
dblPesoTotal = xmlExperienciasP.GetAttrDouble("peso_total");
//Recorre los Puesto requeridos por el puesto y los busca en el CV
for (NomadXML xmlExpP = xmlExperienciasP.FirstChild(); xmlExpP != null; xmlExpP = xmlExpP.Next()) 
{
	//Busca la experiencia dentro de la lista del CV
	if (htaDiasExpCV.ContainsKey(xmlExpP.GetAttr("oi_puesto_exp"))) 
	{
		//Pregunta si tiene la cantidad de dias mínimos
		dblDiasPuesto = xmlExpP.GetAttrDouble("n_coef_dias") * xmlExpP.GetAttrDouble("e_tiempo");
		if (((double)htaDiasExpCV[xmlExpP.GetAttr("oi_puesto_exp")]) > dblDiasPuesto)
			dblResExp = 0.7d;
		else
			dblResExp = 0.5d;
		
		//Busca la experiencia dentro de la lista de areas
		if (htaAreasExpCV.ContainsKey(xmlExpP.GetAttr("oi_puesto_exp"))) 
		{
			for (NomadXML xmlAreaP = xmlExpP.FirstChild(); xmlAreaP != null; xmlAreaP = xmlAreaP.Next()) 
			{
				//Pregunta si tiene el area
				if (((string)htaAreasExpCV[xmlExpP.GetAttr("oi_puesto_exp")]) == xmlAreaP.GetAttr("oi_area_exp"))
				{
					dblResExp = 1d;
					continue;
				}
				else
				{
					if (xmlAreaP.GetAttrBool("exclarea"))
					{
						pbolExcluir = true;
						break;
					}
				}
			}
		} 
		else
			dblResExp = 0d;
	} 
	else
		dblResExp = 0d;
	
	dblPesoExp = xmlExpP.GetAttrDouble("e_peso");

	//Pregunta si el puesto requerido es excluyente
	if (xmlExpP.GetAttrBool("l_excluyente") && dblResExp == 0d) 
	{
		pbolExcluir = true;
		break;
	}

	//Calcula el resultado de al experiencia	
	dblResExp = dblResExp * (dblPesoExp / dblPesoTotal);	
	dblResultado = dblResultado + dblResExp;
}
dblResultado = dblResultado * pdblPonderacion;
NomadEnvironment.GetTrace().Info("RESULTADO -- " + dblResultado + " - Exluye - " + pbolExcluir);
return dblResultado;
